class Solution:
    def strongPasswordCheckerII(self, password):
        if len(password) < 8:
            return False
        specials = set('!@#$%^&*()-+')
        low = up = dig = spec = False
        prev = ''
        for c in password:
            if c == prev:
                return False
            prev = c
            if c.islower():
                low = True
            elif c.isupper():
                up = True
            elif c.isdigit():
                dig = True
            elif c in specials:
                spec = True
        return low and up and dig and spec

